  'home.heroSub': { en: 'by Philip Zimbardo', ka: 'Philip Zimbardo', ru: '\u0424\u0438\u043B\u0438\u043F \u0417\u0438\u043C\u0431\u0430\u0440\u0434\u043E', hy: 'Philip Zimbardo' },
  'home.trustText': { en: 'Trusted by psychology students', ka: '\u10E1\u10E2\u10E3\u10D3\u10D4\u10DC\u10E2\u10D4\u10D1\u10D8\u10E1 \u10DC\u10D3\u10DD\u10D1\u10D8\u10D7', ru: '\u0414\u043E\u0432\u0435\u0440\u044F\u044E\u0442 \u0441\u0442\u0443\u0434\u0435\u043D\u0442\u044B', hy: '\u054E\u057D\u057F\u0561\u0570\u0565\u056C\u056B \u0578\u0582\u057D\u0561\u0576\u0578\u0572\u0576\u0565\u0580\u056B \u056F\u0578\u0572\u0574\u056B\u0581' },
  'home.trustFree': { en: '100% Free', ka: '100% \u10E3\u10E4\u10D0\u10E1\u10DD', ru: '100% \u0431\u0435\u0441\u043F\u043B\u0430\u0442\u043D\u043E', hy: '100% \u0561\u0576\u057E\u0573\u0561\u0580' },
  'home.trustSecure': { en: 'Secure', ka: '\u10E3\u10E1\u10D0\u10E4\u10E0\u10D7\u10EE\u10DD', ru: '\u0411\u0435\u0437\u043E\u043F\u0430\u0441\u043D\u043E', hy: '\u0531\u0576\u057E\u057F\u0561\u0576\u0563' },
