  'home.sectionSub': { en: 'Everything you need to ace your psychology course', ka: '\u10E7\u10D5\u10D4\u10DA\u10D0\u10E4\u10D4\u10E0\u10D8 \u10E0\u10D0\u10EA \u10D2\u10D8\u10ED\u10D8\u10E0\u10D3\u10D4\u10D1\u10D0\u10D7 \u10E4\u10E1\u10D8\u10E5\u10DD\u10DA\u10DD\u10D2\u10D8\u10D8\u10E1 \u10D9\u10E3\u10E0\u10E1\u10D8\u10E1\u10D7\u10D5\u10D8\u10E1', ru: '\u0412\u0441\u0451 \u043D\u0435\u043E\u0431\u0445\u043E\u0434\u0438\u043C\u043E\u0435 \u0434\u043B\u044F \u043A\u0443\u0440\u0441\u0430 \u043F\u0441\u0438\u0445\u043E\u043B\u043E\u0433\u0438\u0438', hy: '\u0531\u0574\u0565\u0576 \u056B\u0576\u0579 \u0578\u0580 \u0561\u0576\u0570\u0580\u0561\u056A\u0565\u0577\u057F \u0567 \u0570\u0578\u0563\u0565\u0562\u0561\u0576\u0578\u0582\u0569\u0575\u0561\u0576 \u0564\u0561\u057D\u0568\u0576\u0569\u0561\u0581\u056B \u0570\u0561\u0574\u0561\u0580' },
