  'home.howBadge': { en: 'How It Works', ka: '\u10E0\u10DD\u10D2\u10DD\u10E0 \u10DB\u10E3\u10E8\u10D0\u10DD\u10D1\u10E1', ru: '\u041A\u0430\u043A \u044D\u0442\u043E \u0440\u0430\u0431\u043E\u0442\u0430\u0435\u0442', hy: '\u053B\u0576\u0579\u057A\u0565\u057D \u0567 \u0561\u0577\u056D\u0561\u057F\u0578\u0582\u0574' },
  'home.howTitle': { en: 'Start Learning in 3 Easy Steps', ka: '\u10D3\u10D0\u10D8\u10EC\u10E7\u10D4 \u10E1\u10EC\u10D0\u10D5\u10DA\u10D0 3 \u10DB\u10D0\u10E0\u10E2\u10D8\u10D5 \u10DC\u10D0\u10D1\u10D8\u10EF\u10E8\u10D8', ru: '\u041D\u0430\u0447\u043D\u0438\u0442\u0435 \u0443\u0447\u0438\u0442\u044C\u0441\u044F \u0437\u0430 3 \u043F\u0440\u043E\u0441\u0442\u044B\u0445 \u0448\u0430\u0433\u0430', hy: '\u054D\u056F\u057D\u0565\u0584 \u057D\u0578\u057E\u0578\u0580\u0565\u056C 3 \u0570\u0565\u0577\u057F \u0584\u0561\u0575\u056C\u0578\u057E' },
  'home.step1Title': { en: 'Create Account', ka: '\u10E8\u10D4\u10E5\u10DB\u10D4\u10DC\u10D8 \u10E3\u10E4\u10D0\u10E1\u10DD \u10D0\u10DC\u10D2\u10D0\u10E0\u10D8\u10E8\u10D8', ru: '\u0421\u043E\u0437\u0434\u0430\u0439\u0442\u0435 \u0430\u043A\u043A\u0430\u0443\u043D\u0442', hy: '\u054D\u057F\u0565\u0572\u056E\u0565\u0584 \u0570\u0561\u0577\u056B\u057E' },
  'home.step1Desc': { en: 'Sign up in seconds and get instant access to all chapters and tools.', ka: '\u10D3\u10D0\u10E0\u10D4\u10D2\u10D8\u10E1\u10E2\u10E0\u10D8\u10E0\u10D3\u10D8\u10D7 \u10EC\u10D0\u10DB\u10D4\u10D1\u10E8\u10D8 \u10D3\u10D0 \u10DB\u10D8\u10D8\u10E6\u10D4\u10D7 \u10EC\u10D5\u10D3\u10DD\u10DB\u10D0.', ru: '\u0417\u0430\u0440\u0435\u0433\u0438\u0441\u0442\u0440\u0438\u0440\u0443\u0439\u0442\u0435\u0441\u044C \u0437\u0430 \u0441\u0435\u043A\u0443\u043D\u0434\u044B \u0438 \u043F\u043E\u043B\u0443\u0447\u0438\u0442\u0435 \u0434\u043E\u0441\u0442\u0443\u043F.', hy: '\u0533\u0580\u0561\u0576\u0581\u057E\u0565\u0584 \u057E\u0561\u0575\u0580\u056F\u0575\u0561\u0576\u0576\u0565\u0580\u0578\u0582\u0574 \u0587 \u057D\u057F\u0561\u0581\u0565\u0584 \u0570\u0561\u057D\u0561\u0576\u0565\u056C\u056B\u0578\u0582\u0569\u0575\u0578\u0582\u0576.' },
  'home.step2Title': { en: 'Study at Your Pace', ka: '\u10D8\u10E1\u10EC\u10D0\u10D5\u10DA\u10D4 \u10E8\u10D4\u10DC\u10D8 \u10E2\u10D4\u10DB\u10DE\u10D8\u10D7', ru: '\u0423\u0447\u0438\u0442\u0435\u0441\u044C \u0432 \u0441\u0432\u043E\u0451\u043C \u0442\u0435\u043C\u043F\u0435', hy: '\u054D\u0578\u057E\u0578\u0580\u0565\u0584 \u0571\u0565\u0580 \u057F\u0565\u0574\u057A\u0578\u057E' },
  'home.step2Desc': { en: 'Read summaries, explore topics, and take quizzes whenever you want.', ka: '\u10EC\u10D0\u10D8\u10D9\u10D8\u10D7\u10EE\u10D4\u10D7 \u10E8\u10D4\u10EF\u10D0\u10DB\u10D4\u10D1\u10D4\u10D1\u10D8, \u10D2\u10D0\u10D8\u10D0\u10E0\u10D4\u10D7 \u10D5\u10D8\u10E5\u10E2\u10DD\u10E0\u10D8\u10DC\u10D4\u10D1\u10D8.', ru: '\u0427\u0438\u0442\u0430\u0439\u0442\u0435, \u0438\u0437\u0443\u0447\u0430\u0439\u0442\u0435 \u0438 \u043F\u0440\u043E\u0445\u043E\u0434\u0438\u0442\u0435 \u0432\u0438\u043A\u0442\u043E\u0440\u0438\u043D\u044B.', hy: '\u053F\u0561\u0580\u0564\u0561\u0581\u0565\u0584, \u0578\u0582\u057D\u0578\u0582\u0574\u0576\u0561\u057D\u056B\u0580\u0565\u0584 \u0587 \u0561\u0576\u0581\u0565\u0584 \u057E\u056B\u056F\u057F\u0578\u0580\u056B\u0576\u0561\u0576\u0565\u0580.' },
  'home.step3Title': { en: 'Track Your Progress', ka: '\u10D7\u10D5\u10D0\u10DA\u10D8 \u10D0\u10D3\u10D4\u10D5\u10DC\u10D4 \u10DE\u10E0\u10DD\u10D2\u10E0\u10D4\u10E1\u10E1', ru: '\u041E\u0442\u0441\u043B\u0435\u0436\u0438\u0432\u0430\u0439\u0442\u0435 \u043F\u0440\u043E\u0433\u0440\u0435\u0441\u0441', hy: '\u0540\u0565\u057F\u0587\u0565\u0584 \u0561\u057C\u0561\u057B\u0568\u0576\u0569\u0561\u0581\u056B\u0576' },
  'home.step3Desc': { en: 'Earn XP, unlock achievements, and watch your knowledge grow.', ka: '\u10DB\u10DD\u10D8\u10DE\u10DD\u10D5\u10D4\u10D7 XP, \u10D2\u10D0\u10DC\u10D1\u10DA\u10DD\u10D9\u10D4\u10D7 \u10DB\u10D8\u10E6\u10EC\u10D4\u10D5\u10D4\u10D1\u10D8.', ru: '\u0417\u0430\u0440\u0430\u0431\u0430\u0442\u044B\u0432\u0430\u0439\u0442\u0435 XP, \u043E\u0442\u043A\u0440\u044B\u0432\u0430\u0439\u0442\u0435 \u0434\u043E\u0441\u0442\u0438\u0436\u0435\u043D\u0438\u044F.', hy: '\u054E\u0561\u057D\u057F\u0561\u056F\u0565\u0584 XP, \u0562\u0561\u0581\u0565\u0584 \u0576\u057E\u0561\u0573\u0578\u0582\u0574\u0576\u0565\u0580.' },
  'home.quote': { en: 'Psychology is the science of mental life, both of its phenomena and their conditions.', ka: '\u10E4\u10E1\u10D8\u10E5\u10DD\u10DA\u10DD\u10D2\u10D8\u10D0 \u10D0\u10E0\u10D8\u10E1 \u10DB\u10D4\u10EA\u10DC\u10D8\u10D4\u10E0\u10D4\u10D1\u10D0 \u10E4\u10E1\u10D8\u10E5\u10D8\u10D9\u10E3\u10E0\u10D8 \u10EA\u10EE\u10DD\u10D5\u10E0\u10D4\u10D1\u10D8\u10E1 \u10E8\u10D4\u10E1\u10D0\u10EE\u10D4\u10D1.', ru: '\u041F\u0441\u0438\u0445\u043E\u043B\u043E\u0433\u0438\u044F \u2014 \u044D\u0442\u043E \u043D\u0430\u0443\u043A\u0430 \u043E \u043F\u0441\u0438\u0445\u0438\u0447\u0435\u0441\u043A\u043E\u0439 \u0436\u0438\u0437\u043D\u0438.', hy: '\u0540\u0578\u0563\u0565\u0562\u0561\u0576\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568 \u0570\u0578\u0563\u0565\u056F\u0561\u0576 \u056F\u0575\u0561\u0576\u0584\u056B \u0563\u056B\u057F\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576 \u0567.' },
  'home.readFaq': { en: 'Read FAQ', ka: 'FAQ', ru: '\u0427\u0430\u0421\u0412', hy: 'FAQ' },

